(()=>{var e={};function t(t){fetch(t).then(e=>e.text()).then(n=>{let o=new DOMParser,s=o.parseFromString(n,"text/html");document.getElementById("main-content").innerHTML=s.getElementById("main-content").innerHTML,document.getElementsByTagName("title")[0].innerHTML=s.getElementsByTagName("title")[0].innerHTML,e[t]=s,window.scrollTo(0,0)}).catch(e=>console.warn(e))}})()